sql:
SELECT SUM(area) AS total_area
FROM land_parcels
WHERE owner_id = (SELECT owner_id FROM owners WHERE owner_name = 'John Doe');

external_knowledge:
- 'category' refers to the label name of the land parcel;
- 'dimensions' include area, perimeter, height, and width;
- 'space' is calculated as the product of height and width, representing volume;
- 'person behind each plot' refers to the owner name.

sql:
SELECT parcel_id, area
FROM land_parcels
WHERE area > (SELECT AVG(area) FROM land_parcels);

SELECT area
FROM land_parcels
WHERE area > (SELECT AVG(area) FROM land_parcels);

SELECT AVG(perimeter) AS Average_Perimeter 
FROM land_parcels 
WHERE label = 1;

external_knowledge:
- "categories" refers to the 'label' of land parcels; 
- "the first month of 2023" refers to the time range from January 1 to January 31, 2023;
- "more than the usual space per type" implies that the total area of each category is greater than the average area of all land parcels;
- "total space they occupy" refers to the total area of land parcels under each category.
